class Solution:
    def solve(self, nums: list[int], target: int) -> bool:
        if len(nums) == 0 or len(nums) == 1:
            return nums[0] == target
        left, right = 0, len(nums) - 1
        while left <= right:
            mid = (left + right) // 2
            if nums[mid] == target:
                return True
            elif nums[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        return False

def main():
    target = int(input())
    n = int(input())
    nums = list(map(int, input().split()))
    solution = Solution()
    print(solution.solve(nums, target))

