class Solution:
{
public:
   bool solve(vector<int>& nums) {
       if (nums.size() == 0 || nums.size() == 1) return nums[0] == target;
       int left = 0, right = nums.size() - 1;
       while (left <= right) {
           int mid = left + (right - left) / 2;
           if (nums[mid] == target) return true;
           if (nums[mid] < target) left = mid + 1;
           else right = mid - 1;
       }
       return false;
   }
};

int main() {
   int target;
   cin >> target;
   int n;
   cin >> n;
   for (int i = 0; i < n; i++) {
       int x;
       cin >> x;
       nums.push_back(x);
   }
   Solution solution;
   solution.solve(nums);
   cout << (solution.solve(nums) ? "Yes" : "No") << endl;
   return 0;
}
